"""sklearn.isotonic — Isotonic regression."""
import numpy as np
from sklearn.base import BaseEstimator, RegressorMixin, TransformerMixin


class IsotonicRegression(BaseEstimator, RegressorMixin, TransformerMixin):
    """Isotonic (monotonically increasing) regression.

    Parameters
    ----------
    increasing : bool, default=True
    out_of_bounds : str, default='clip'
    """

    def __init__(self, increasing=True, out_of_bounds='clip'):
        self.increasing = increasing
        self.out_of_bounds = out_of_bounds

    def fit(self, X, y, sample_weight=None):
        X = np.asarray(X, dtype=float).ravel()
        y = np.asarray(y, dtype=float).ravel()
        order = np.argsort(X)
        X, y = X[order], y[order]
        if sample_weight is not None:
            w = np.asarray(sample_weight, dtype=float).ravel()[order]
        else:
            w = np.ones_like(y)

        if not self.increasing:
            y = -y

        # Pool Adjacent Violators
        n = len(y)
        result = y.copy()
        weights = w.copy()
        i = 0
        while i < n - 1:
            if result[i] > result[i + 1]:
                # Merge blocks
                wsum = weights[i] + weights[i + 1]
                result[i] = (weights[i] * result[i] + weights[i + 1] * result[i + 1]) / wsum
                weights[i] = wsum
                result = np.delete(result, i + 1)
                weights = np.delete(weights, i + 1)
                X_arr = np.delete(X, i + 1) if len(X) == n else X
                n = len(result)
                if i > 0:
                    i -= 1
            else:
                i += 1

        if not self.increasing:
            result = -result

        # Store fitted values by expanding blocks back
        self.X_thresholds_ = X
        self.y_thresholds_ = np.interp(X, np.linspace(X.min(), X.max(), len(result)), result)
        self.X_min_ = X.min()
        self.X_max_ = X.max()
        return self

    def predict(self, X):
        return self.transform(X)

    def transform(self, X):
        X = np.asarray(X, dtype=float).ravel()
        result = np.interp(X, self.X_thresholds_, self.y_thresholds_)
        if self.out_of_bounds == 'clip':
            result = np.clip(result, self.y_thresholds_.min(), self.y_thresholds_.max())
        return result
